class FoodItem {
  final String name;
  final String amount;
  final String gramsEstimate;

  /// A single emoji representing the food, generated by the AI alongside
  /// the rest of the item. May be empty for plans saved before this field
  /// existed — [foodGlyph] in the UI layer covers that fallback.
  final String glyph;

  const FoodItem({
    required this.name,
    required this.amount,
    required this.gramsEstimate,
    this.glyph = '',
  });

  Map<String, dynamic> toJson() => {
        'name': name,
        'amount': amount,
        'grams_estimate': gramsEstimate,
        'glyph': glyph,
      };

  factory FoodItem.fromJson(Map<String, dynamic> json) => FoodItem(
        name: json['name'] as String,
        amount: json['amount'] as String,
        gramsEstimate: json['grams_estimate'] as String? ?? '',
        glyph: json['glyph'] as String? ?? '',
      );
}

class MealEntry {
  final String time;
  final String meal;
  final int estimatedCalories;
  final List<FoodItem> foods;

  const MealEntry({
    required this.time,
    required this.meal,
    required this.estimatedCalories,
    required this.foods,
  });

  MealEntry copyWith({List<FoodItem>? foods}) => MealEntry(
        time: time,
        meal: meal,
        estimatedCalories: estimatedCalories,
        foods: foods ?? this.foods,
      );

  Map<String, dynamic> toJson() => {
        'time': time,
        'meal': meal,
        'estimated_calories': estimatedCalories,
        'foods': foods.map((f) => f.toJson()).toList(),
      };

  factory MealEntry.fromJson(Map<String, dynamic> json) => MealEntry(
        time: json['time'] as String,
        meal: json['meal'] as String,
        estimatedCalories: json['estimated_calories'] as int,
        foods: (json['foods'] as List)
            .map((f) => FoodItem.fromJson(f as Map<String, dynamic>))
            .toList(),
      );
}

