    required this.fat,
    required this.water,
  });

  Map<String, dynamic> toJson() => {
        'calories': calories,
        'protein': protein,
        'carbs': carbs,
        'fat': fat,
        'water': water,
      };

  factory DailyTargets.fromJson(Map<String, dynamic> json) => DailyTargets(
        calories: json['calories'] as String,
