class ProfileSummary {
  final String gender;
  final String dietType;
  final String country;
  final String mealCountPreference;

  const ProfileSummary({
    required this.gender,
    required this.dietType,
    required this.country,
    required this.mealCountPreference,
  });

  Map<String, dynamic> toJson() => {
        'gender': gender,
        'diet_type': dietType,
        'country': country,
        'meal_count_preference': mealCountPreference,
      };

  factory ProfileSummary.fromJson(Map<String, dynamic> json) => ProfileSummary(
        gender: json['gender'] as String,
        dietType: json['diet_type'] as String,
        country: json['country'] as String,
        mealCountPreference: json['meal_count_preference'] as String,
      );
}

class DailyPlan {
  final String goal;
  final ProfileSummary profileSummary;
  final DailyTargets dailyTargets;
  final List<MealEntry> schedule;
  final String disclaimer;

  const DailyPlan({
    required this.goal,
    required this.profileSummary,
    required this.dailyTargets,
    required this.schedule,
    required this.disclaimer,
  });

  int get totalCalories =>
      schedule.fold(0, (sum, m) => sum + m.estimatedCalories);

  DailyPlan copyWith({List<MealEntry>? schedule}) => DailyPlan(
        goal: goal,
        profileSummary: profileSummary,
        dailyTargets: dailyTargets,
        schedule: schedule ?? this.schedule,
        disclaimer: disclaimer,
      );

  Map<String, dynamic> toJson() => {
        'goal': goal,
        'profile_summary': profileSummary.toJson(),
        'daily_targets': dailyTargets.toJson(),
        'schedule': schedule.map((m) => m.toJson()).toList(),
        'disclaimer': disclaimer,
      };

  factory DailyPlan.fromJson(Map<String, dynamic> json) => DailyPlan(
        goal: json['goal'] as String,
        profileSummary:
            ProfileSummary.fromJson(json['profile_summary'] as Map<String, dynamic>),
        dailyTargets: DailyTargets.fromJson(json['daily_targets'] as Map<String, dynamic>),
        schedule: (json['schedule'] as List)
            .map((m) => MealEntry.fromJson(m as Map<String, dynamic>))
            .toList(),
        disclaimer: json['disclaimer'] as String? ?? '',
      );
}
